import{c as a,Q as n,j as e,m as t}from"./chunks/framework.CQqJojvj.js";const b=JSON.parse('{"title":"IM 即时通讯项目","description":"","frontmatter":{},"headers":[],"relativePath":"projects/im-project.md","filePath":"projects/im-project.md","lastUpdated":null}'),l={name:"projects/im-project.md"};function i(p,s,r,d,o,c){return n(),e("div",null,[...s[0]||(s[0]=[t(`<h1 id="im-即时通讯项目" tabindex="-1">IM 即时通讯项目 <a class="header-anchor" href="#im-即时通讯项目" aria-label="Permalink to &quot;IM 即时通讯项目&quot;">​</a></h1><blockquote><p>基于 Netty 的即时通讯系统，支持单聊、群聊、消息推送、离线消息。</p></blockquote><hr><h2 id="项目概述" tabindex="-1">项目概述 <a class="header-anchor" href="#项目概述" aria-label="Permalink to &quot;项目概述&quot;">​</a></h2><h3 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to &quot;核心功能&quot;">​</a></h3><ul><li><strong>用户管理</strong> — 注册、登录、好友管理</li><li><strong>单聊</strong> — 点对点实时消息</li><li><strong>群聊</strong> — 群组创建、加入退出、群消息</li><li><strong>离线消息</strong> — 用户离线时消息暂存，上线后推送</li><li><strong>消息可靠性</strong> — ACK 确认、消息去重、重发机制</li></ul><h3 id="技术栈" tabindex="-1">技术栈 <a class="header-anchor" href="#技术栈" aria-label="Permalink to &quot;技术栈&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">层级</th><th style="text-align:left;">技术</th></tr></thead><tbody><tr><td style="text-align:left;">网络通信</td><td style="text-align:left;">Netty（Reactor 多线程模型）</td></tr><tr><td style="text-align:left;">协议</td><td style="text-align:left;">TCP 长连接 + 自定义二进制协议</td></tr><tr><td style="text-align:left;">消息队列</td><td style="text-align:left;">Redis Stream（离线消息存储）</td></tr><tr><td style="text-align:left;">服务发现</td><td style="text-align:left;">ZooKeeper</td></tr><tr><td style="text-align:left;">数据存储</td><td style="text-align:left;">MySQL + Redis</td></tr><tr><td style="text-align:left;">架构</td><td style="text-align:left;">Spring Boot</td></tr></tbody></table><hr><h2 id="架构设计" tabindex="-1">架构设计 <a class="header-anchor" href="#架构设计" aria-label="Permalink to &quot;架构设计&quot;">​</a></h2><h3 id="整体架构" tabindex="-1">整体架构 <a class="header-anchor" href="#整体架构" aria-label="Permalink to &quot;整体架构&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                  客户端 (Mobile/Web)               │</span></span>
<span class="line"><span>└──────────────────────┬───────────────────────────┘</span></span>
<span class="line"><span>                       │ TCP 长连接</span></span>
<span class="line"><span>                       ▼</span></span>
<span class="line"><span>┌──────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│              接入层 (Netty Server)                 │</span></span>
<span class="line"><span>│  ├─ 连接管理（ChannelGroup）                       │</span></span>
<span class="line"><span>│  ├─ 协议编解码（自定义二进制/Protobuf）               │</span></span>
<span class="line"><span>│  ├─ 心跳检测（IdleStateHandler）                   │</span></span>
<span class="line"><span>│  └─ 限流（令牌桶）                                 │</span></span>
<span class="line"><span>└──────────────────────┬───────────────────────────┘</span></span>
<span class="line"><span>                       │</span></span>
<span class="line"><span>                       ▼</span></span>
<span class="line"><span>┌──────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│              业务逻辑层                             │</span></span>
<span class="line"><span>│  ├─ 用户服务                                       │</span></span>
<span class="line"><span>│  ├─ 消息服务（单聊/群聊/离线消息）                    │</span></span>
<span class="line"><span>│  └─ 路由转发（根据 userId 找到对应的 Netty 节点）     │</span></span>
<span class="line"><span>└──────────────────────┬───────────────────────────┘</span></span>
<span class="line"><span>                       │</span></span>
<span class="line"><span>          ┌────────────┼────────────┐</span></span>
<span class="line"><span>          ▼            ▼            ▼</span></span>
<span class="line"><span>     ┌────────┐  ┌────────┐  ┌──────────┐</span></span>
<span class="line"><span>     │ MySQL  │  │ Redis  │  │ZooKeeper │</span></span>
<span class="line"><span>     └────────┘  └────────┘  └──────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br></div></div><h3 id="长连接管理" tabindex="-1">长连接管理 <a class="header-anchor" href="#长连接管理" aria-label="Permalink to &quot;长连接管理&quot;">​</a></h3><p><strong>用户 → Channel 映射：</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Map&lt;userId, Channel&gt; userChannelMap  // 内存中维护</span></span>
<span class="line"><span>Redis: user:{userId}:server → serverIp:port  // 跨节点路由</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><strong>心跳检测：</strong></p><div class="language-java vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Netty IdleStateHandler 配置</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">pipeline.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">addLast</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">new</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> IdleStateHandler</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">30</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, TimeUnit.SECONDS));</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 30 秒未收到任何数据，触发 USER_EVENT_IDLE → 关闭连接</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p><strong>为什么不用 WebSocket？</strong></p><p>TCP 长连接 + 自定义二进制协议比 WebSocket 更高效：</p><ul><li>二进制协议更紧凑（减少带宽）</li><li>更灵活的自定义编解码</li><li>更好的可控性（连接池、重连策略）</li></ul><p>如果面向浏览器客户端，则必须使用 WebSocket。</p><h3 id="消息可靠性保证" tabindex="-1">消息可靠性保证 <a class="header-anchor" href="#消息可靠性保证" aria-label="Permalink to &quot;消息可靠性保证&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>发送方 → 消息持久化(Redis) → 发送到接收方</span></span>
<span class="line"><span>        ↓ 未收到 ACK</span></span>
<span class="line"><span>        重试机制（最多 3 次）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><ul><li><strong>ACK 确认：</strong> 每条消息带 msgId，接收方收到后回 ACK，发送方超时未收到则重发</li><li><strong>消息去重：</strong> 客户端用 msgId 去重，防止重复推送</li><li><strong>离线消息：</strong> 接收方不在线时消息存 Redis List，上线后批量拉取</li></ul><h3 id="路由转发" tabindex="-1">路由转发 <a class="header-anchor" href="#路由转发" aria-label="Permalink to &quot;路由转发&quot;">​</a></h3><p><strong>问题：</strong> 用户 A 和用户 B 可能连接在不同 Netty 节点上。</p><p><strong>解决：</strong></p><ol><li>每个 Netty 节点在 ZooKeeper 注册临时节点：<code>/im/servers/{serverId}</code></li><li>用户登录时记录：<code>Redis: user:{userId}:server → serverId</code></li><li>发消息时先查接收方所在节点： <ul><li>本节点 → 直接发送</li><li>其他节点 → 通过内部 HTTP/RPC 转发到目标节点</li></ul></li></ol><hr><h2 id="面试话术" tabindex="-1">面试话术 <a class="header-anchor" href="#面试话术" aria-label="Permalink to &quot;面试话术&quot;">​</a></h2><h3 id="高频问题" tabindex="-1">高频问题 <a class="header-anchor" href="#高频问题" aria-label="Permalink to &quot;高频问题&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">问题</th><th style="text-align:left;">回答要点</th></tr></thead><tbody><tr><td style="text-align:left;">&quot;为什么用 Netty？&quot;</td><td style="text-align:left;">NIO 多路复用、零拷贝、高性能吞吐；Reactor 线程模型；成熟的编解码器和处理器链</td></tr><tr><td style="text-align:left;">&quot;如何保证消息不丢？&quot;</td><td style="text-align:left;">消息持久化 + ACK 确认 + 超时重传 + 消息去重</td></tr><tr><td style="text-align:left;">&quot;离线消息怎么处理？&quot;</td><td style="text-align:left;">Redis List 暂存离线消息，用户上线后批量拉取并一次性推送</td></tr><tr><td style="text-align:left;">&quot;服务怎么扩容？&quot;</td><td style="text-align:left;">ZooKeeper 服务发现，新节点注册后自动加入集群；通过用户 ID 哈希分配连接</td></tr><tr><td style="text-align:left;">&quot;心跳为什么需要？&quot;</td><td style="text-align:left;">检测死连接（网络断开、客户端崩溃等极端情况），及时清理 Channel，释放资源</td></tr></tbody></table><h3 id="可能的追问" tabindex="-1">可能的追问 <a class="header-anchor" href="#可能的追问" aria-label="Permalink to &quot;可能的追问&quot;">​</a></h3><p><strong>Q: 如果有 10 万用户同时在线，如何优化？</strong></p><blockquote><p>&quot;1) Netty Boss/Worker 线程池调整，Boss 线程 1-2 个，Worker 线程 = CPU 核数×2；2) 根据 userId hash 到不同 Netty 节点做水平扩展；3) 消息推送使用批量方式，减少 IO 次数；4) Redis 集群化，消息队列使用 Redis Cluster&quot;</p></blockquote><p><strong>Q: 如何保证消息有序？</strong></p><blockquote><p>&quot;单聊场景：相同 sender→receiver 的消息加单调递增序号，接收方按序号排列。群聊场景：使用 Kafka 分区（同一群聊消息发到同一分区）保证分区内有序，或服务端加序列号。&quot;</p></blockquote><hr>`,38)])])}const u=a(l,[["render",i]]);export{b as __pageData,u as default};
